/**
 * @summary Get recently added clients
 */
export const getGetDashboardRecentClientsUrl = (
  params?: GetDashboardRecentClientsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dashboard/recent-clients?${stringifiedParams}`
    : `/api/dashboard/recent-clients`;
};

export const getDashboardRecentClients = async (
  params?: GetDashboardRecentClientsParams,
  options?: RequestInit,
): Promise<Client[]> => {
  return customFetch<Client[]>(getGetDashboardRecentClientsUrl(params), {
    ...options,
    method: "GET",
  });
};

